<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Conway's Game of Life</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }

  body {
    background: #0a0a0f;
    color: #e0e0e0;
    font-family: 'Segoe UI', system-ui, -apple-system, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    overflow: hidden;
    user-select: none;
  }

  h1 {
    font-size: 1.6rem;
    margin-bottom: 12px;
    background: linear-gradient(90deg, #ff6fd8, #3813c2);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    letter-spacing: 2px;
    text-transform: uppercase;
  }

  #life {
    border: 2px solid #2a2a3a;
    border-radius: 8px;
    cursor: crosshair;
    display: block;
    background: #0d0d14;
    box-shadow: 0 0 40px rgba(56, 19, 194, 0.15), 0 0 80px rgba(255, 111, 216, 0.05);
  }

  .controls {
    display: flex;
    gap: 10px;
    margin-top: 16px;
    flex-wrap: wrap;
    justify-content: center;
  }

  button {
    background: #1a1a2e;
    color: #c8c8d8;
    border: 1.5px solid #3a3a5a;
    padding: 10px 22px;
    font-size: 0.95rem;
    border-radius: 6px;
    cursor: pointer;
    transition: all 0.15s ease;
    font-weight: 600;
    letter-spacing: 0.5px;
  }

  button:hover {
    background: #2a2a4e;
    border-color: #6a6aaa;
    color: #fff;
    transform: translateY(-1px);
    box-shadow: 0 4px 12px rgba(56, 19, 194, 0.3);
  }

  button:active {
    transform: translateY(0);
  }

  button#play.active {
    background: #1a3a1e;
    border-color: #2ecc71;
    color: #2ecc71;
    box-shadow: 0 0 16px rgba(46, 204, 113, 0.2);
  }

  .info {
    margin-top: 10px;
    font-size: 0.8rem;
    color: #5a5a7a;
    letter-spacing: 1px;
  }

  #gen-counter {
    color: #ff6fd8;
    font-weight: bold;
  }
</style>
</head>
<body>

<h1>Game of Life</h1>
<canvas id="life"></canvas>
<div class="controls">
  <button id="step">⏭ Step</button>
  <button id="play">▶ Play</button>
  <button id="random">🎲 Random</button>
  <button id="clear">✕ Clear</button>
</div>
<div class="info">Generation: <span id="gen-counter">0</span></div>

<script>
(function() {
  // Grid dimensions (cells)
  const W = 50;
  const H = 50;

  // Canvas sizing — at least 400×400 CSS pixels
  const CELL_SIZE = Math.floor(Math.min(
    (window.innerWidth - 60) / W,
    (window.innerHeight - 180) / H,
    16
  ));
  const CANVAS_SIZE = CELL_SIZE * W;

  // State arrays — two buffers for simultaneous update
  let grid = new Uint8Array(W * H);
  let nextGrid = new Uint8Array(W * H);
  let generation = 0;

  // Canvas setup
  const canvas = document.getElementById('life');
  const ctx = canvas.getContext('2d');
  canvas.width = CANVAS_SIZE;
  canvas.height = CANVAS_SIZE;
  canvas.style.width = CANVAS_SIZE + 'px';
  canvas.style.height = CANVAS_SIZE + 'px';

  // --- Simulation ---

  function idx(x, y) { return y * W + x; }

  function get(x, y) {
    if (x < 0 || x >= W || y < 0 || y >= H) return 0;
    return grid[idx(x, y)];
  }

  function set(x, y, v) {
    if (x < 0 || x >= W || y < 0 || y >= H) return;
    grid[idx(x, y)] = v ? 1 : 0;
  }

  function step() {
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        let neighbors = 0;
        for (let dy = -1; dy <= 1; dy++) {
          for (let dx = -1; dx <= 1; dx++) {
            if (dx === 0 && dy === 0) continue;
            neighbors += get(x + dx, y + dy);
          }
        }
        const i = idx(x, y);
        if (grid[i]) {
          // Live cell survives with 2 or 3 neighbors
          nextGrid[i] = (neighbors === 2 || neighbors === 3) ? 1 : 0;
        } else {
          // Dead cell becomes alive with exactly 3 neighbors
          nextGrid[i] = (neighbors === 3) ? 1 : 0;
        }
      }
    }
    // Swap buffers — simultaneous update applied all at once
    let tmp = grid;
    grid = nextGrid;
    nextGrid = tmp;
    generation++;
    document.getElementById('gen-counter').textContent = generation;
    draw();
  }

  function clear() {
    grid.fill(0);
    nextGrid.fill(0);
    generation = 0;
    document.getElementById('gen-counter').textContent = '0';
    draw();
  }

  // --- Rendering ---

  const aliveColor = '#ff6fd8';
  const aliveGlow = 'rgba(255, 111, 216, 0.3)';
  const deadColor = '#0d0d14';
  const gridLineColor = '#1a1a2e';

  function draw() {
    ctx.fillStyle = deadColor;
    ctx.fillRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);

    // Draw grid lines
    ctx.strokeStyle = gridLineColor;
    ctx.lineWidth = 0.5;
    for (let i = 0; i <= W; i++) {
      const pos = i * CELL_SIZE + 0.5;
      ctx.beginPath();
      ctx.moveTo(pos, 0);
      ctx.lineTo(pos, CANVAS_SIZE);
      ctx.stroke();
      ctx.beginPath();
      ctx.moveTo(0, pos);
      ctx.lineTo(CANVAS_SIZE, pos);
      ctx.stroke();
    }

    // Draw alive cells with glow effect
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        if (grid[idx(x, y)]) {
          const px = x * CELL_SIZE;
          const py = y * CELL_SIZE;
          const pad = 1;

          // Glow
          ctx.fillStyle = aliveGlow;
          ctx.fillRect(px - 2, py - 2, CELL_SIZE + 4, CELL_SIZE + 4);

          // Cell body
          ctx.fillStyle = aliveColor;
          ctx.fillRect(px + pad, py + pad, CELL_SIZE - pad * 2, CELL_SIZE - pad * 2);

          // Highlight
          const highlightPad = Math.max(1, Math.floor(CELL_SIZE / 6));
          ctx.fillStyle = 'rgba(255, 255, 255, 0.18)';
          ctx.fillRect(px + pad, py + pad, CELL_SIZE - pad * 2, highlightPad);
        }
      }
    }
  }

  // --- Painting (click & drag) ---

  let painting = false;
  let paintValue = 1; // what to set when painting

  function cellFromEvent(e) {
    const rect = canvas.getBoundingClientRect();
    const scaleX = CANVAS_SIZE / rect.width;
    const scaleY = CANVAS_SIZE / rect.height;
    const mx = (e.clientX - rect.left) * scaleX;
    const my = (e.clientY - rect.top) * scaleY;
    const cx = Math.floor(mx / CELL_SIZE);
    const cy = Math.floor(my / CELL_SIZE);
    if (cx >= 0 && cx < W && cy >= 0 && cy < H) return { x: cx, y: cy };
    return null;
  }

  canvas.addEventListener('mousedown', function(e) {
    e.preventDefault();
    painting = true;
    const cell = cellFromEvent(e);
    if (cell) {
      paintValue = grid[idx(cell.x, cell.y)] ? 0 : 1;
      set(cell.x, cell.y, paintValue);
      draw();
    }
  });

  canvas.addEventListener('mousemove', function(e) {
    if (!painting) return;
    const cell = cellFromEvent(e);
    if (cell) {
      set(cell.x, cell.y, paintValue);
      draw();
    }
  });

  window.addEventListener('mouseup', function() {
    painting = false;
  });

  // Touch support
  canvas.addEventListener('touchstart', function(e) {
    e.preventDefault();
    const touch = e.touches[0];
    const mouseEvent = new MouseEvent('mousedown', { clientX: touch.clientX, clientY: touch.clientY });
    canvas.dispatchEvent(mouseEvent);
  }, { passive: false });

  canvas.addEventListener('touchmove', function(e) {
    e.preventDefault();
    const touch = e.touches[0];
    const mouseEvent = new MouseEvent('mousemove', { clientX: touch.clientX, clientY: touch.clientY });
    window.dispatchEvent(mouseEvent);
  }, { passive: false });

  canvas.addEventListener('touchend', function() {
    window.dispatchEvent(new MouseEvent('mouseup'));
  });

  // --- Random seeding ---

  function randomize(density) {
    density = density || 0.3;
    for (let i = 0; i < W * H; i++) {
      grid[i] = Math.random() < density ? 1 : 0;
    }
    generation = 0;
    document.getElementById('gen-counter').textContent = '0';
    draw();
  }

  // --- Auto-play ---

  let playing = false;
  let playInterval = null;
  const PLAY_SPEED = 80; // ms per generation

  function togglePlay() {
    playing = !playing;
    const btn = document.getElementById('play');
    if (playing) {
      btn.textContent = '⏸ Pause';
      btn.classList.add('active');
      playInterval = setInterval(step, PLAY_SPEED);
    } else {
      btn.textContent = '▶ Play';
      btn.classList.remove('active');
      clearInterval(playInterval);
      playInterval = null;
    }
  }

  // --- Button handlers ---

  document.getElementById('step').addEventListener('click', step);
  document.getElementById('play').addEventListener('click', togglePlay);
  document.getElementById('random').addEventListener('click', function() { randomize(0.3); });
  document.getElementById('clear').addEventListener('click', clear);

  // --- Expose API on window ---

  window.life = {
    w: W,
    h: H,
    get: get,
    set: set,
    step: step,
    clear: clear,
    // Extra helpers for grading convenience
    _grid: grid,
    _nextGrid: nextGrid,
    _generation: function() { return generation; }
  };

  // Initial draw
  draw();
})();
</script>
</body>
</html>
